async (params, browser) => {
  // Open Google Calendar
  await browser.open('https://calendar.google.com/calendar/r')

  // Wait for calendar to load
  await browser.waitForSelector('[role=\'main\'], [data-eventid], .FAxxKc', 20000)

  // Build eventedit URL and navigate to pre-filled event form
  const navigate_to_form = await browser.evaluate(`const title = params.title; const date = params.date.replace(/-/g, ''); const time = params.time; const duration = parseInt(params.duration) || 60; const desc = params.description; let dates = ''; if (time && date) { const [h, m] = time.split(':'); const startMin = parseInt(h) * 60 + (parseInt(m) || 0); const endMin = startMin + duration; const endH = String(Math.floor(endMin / 60) % 24).padStart(2, '0'); const endM = String(endMin % 60).padStart(2, '0'); dates = date + 'T' + String(h).padStart(2, '0') + String(m || '00').padStart(2, '0') + '00/' + date + 'T' + endH + endM + '00'; } else if (date) { const d = new Date(parseInt(date.slice(0,4)), parseInt(date.slice(4,6))-1, parseInt(date.slice(6,8))+1); const next = d.getFullYear() + String(d.getMonth()+1).padStart(2,'0') + String(d.getDate()).padStart(2,'0'); dates = date + '/' + next; } const p = new URLSearchParams(); p.set('text', title); if (dates) p.set('dates', dates); if (desc) p.set('details', desc); window.location.href = 'https://calendar.google.com/calendar/r/eventedit?' + p.toString(); return { navigating: true, title: title, date: params.date, time: time || 'all-day' }`)

  // Wait for event creation form to fully load
  await browser.wait(5000)

  // Wait for event creation form
  await browser.waitForSelector('input[aria-label=\'Title\'], [data-key=\'title\'], input[placeholder=\'Add title\'], input[aria-label=\'Add title\'], [aria-label=\'Save\']', 20000)

  // Let form fully render
  await browser.wait(1000)

  // Save the event
  const save_result = await browser.evaluate(`const saveBtn = document.querySelector('[aria-label="Save"], button[data-tooltip="Save"], button[type="submit"]'); if (!saveBtn) { const allButtons = [...document.querySelectorAll('button, [role="button"]')]; const save = allButtons.find(b => (b.textContent || '').trim().toLowerCase() === 'save'); if (save) { save.click(); } else { return { error: 'Could not find Save button' }; } } else { saveBtn.click(); } await new Promise(r => setTimeout(r, 3000)); return { success: true, title: params.title, date: params.date, time: params.time || 'all-day', url: window.location.href }`)

  return save_result
}
